void read(Tokeniser t, CharacterReader r) {
    char c = r.consume();
    StringBuilder sb = new StringBuilder();
    boolean hasSlash = false;
    while(!Character.isWhitespace(c)){ 
        if(c == '/'){
            hasSlash = true;  
        }else if (!hasSlash && !Character.isLetterOrDigit(c)) {
            throw error(r);
        } else if (hasSlash && !Character.isLetterOrDigit(c)) {
            throw error(r);
        }else{
            sb.append(c);    
        }

        c = r.next();
    }
    if (!Character.isUpperCase(sb.charAt(0))) {
        t.attrKeyPending.setLength(0);
        t.emitAttrKeyPending(sb.toString());
        t.emitCurrentNodeIfNecessary(true);
        t.currentNode.attributes.put(sb.toString(), "");
        t.transition(AfterAttributeValue);
    } else {
        t.tagPending.name = sb.toString().toLowerCase();
        t.emitTagPending();
        t.currentNode = null;
        t.stateHistory.push(t.state);
        t.state = BeforeStartTag + 1;
    }
}

